INSERT INTO BlogArticle (id, slug, title, excerpt, content, published, image, createdAt, updatedAt, meta_title, meta_description, og_image, keywords, noindex) VALUES ('d084cac8-ce55-410c-bb2c-cdab36ceb5d4', 'https://totoksrimurnisewatendasolo.biz.id/#gallery', 'SEWA TENDA SOLO MURAH', 'Butuh sewa tenda di Solo dengan harga murah? Tenda Totok Sri Murni telah  berpengalaman sejak 1998 sebagai solusi terpercaya untuk kebutuhan tenda  pernikahan, hajatan, dan acara outdoor di wilayah Solo dan sekitarnya.  Hubungi kami sekarang di 0851-6363-3221.', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"Mencari jasa sewa tenda Solo murah yang terpercaya dan berpengalaman? Totok Sri Murni adalah pilihan tepat untuk Anda. Berpengalaman sejak 1998, kami telah melayani ribuan acara di Solo dan sekitarnya dengan hasil memuaskan. Mulai dari pernikahan, khitanan, reuni, syukuran, hingga acara perusahaan — semua bisa kami tangani dengan profesional."}]},{"type":"paragraph","content":[{"type":"text","text":"Jenis Tenda yang Tersedia"}]},{"type":"paragraph","content":[{"type":"text","text":"Kami menyediakan berbagai pilihan tenda sesuai kebutuhan dan budget acara Anda:"}]},{"type":"paragraph","content":[{"type":"text","text":"Tenda VIP / Pesta – Cocok untuk resepsi pernikahan dan hajatan besar"}]},{"type":"paragraph","content":[{"type":"text","text":"Tenda Sarnafil – Tampilan elegan dengan atap transparan, kesan mewah"}]},{"type":"paragraph","content":[{"type":"text","text":"Tenda Serut – Pilihan populer untuk acara outdoor yang fleksibel"}]},{"type":"paragraph","content":[{"type":"text","text":"Tenda Rangka – Kokoh dan tahan angin untuk segala cuaca"}]},{"type":"paragraph","content":[{"type":"text","text":"Tenda Biasa / Terpal – Pilihan ekonomis untuk acara sederhana"}]},{"type":"paragraph","content":[{"type":"text","text":"Selain Tenda, Kami Juga Menyewakan"}]},{"type":"paragraph","content":[{"type":"text","text":"Totok Sri Murni bukan hanya menyewakan tenda. Kami juga menyediakan perlengkapan acara lainnya secara lengkap:"}]},{"type":"paragraph","content":[{"type":"text","text":"🪑 Kursi VIP + Cover"}]},{"type":"paragraph","content":[{"type":"text","text":"🛋️ Sofa"}]},{"type":"paragraph","content":[{"type":"text","text":"🍽️ Meja Prasmanan"}]},{"type":"paragraph","content":[{"type":"text","text":"🎵 Sound System"}]},{"type":"paragraph","content":[{"type":"text","text":"💨 Kipas Blower & Blower Air"}]},{"type":"paragraph","content":[{"type":"text","text":"🎪 Panggung + Karpet"}]},{"type":"paragraph","content":[{"type":"text","text":"🍶 Bolo Pecah dan perlengkapan pesta lainnya"}]},{"type":"paragraph","content":[{"type":"text","text":"Mengapa Memilih Totok Sri Murni?"}]},{"type":"paragraph","content":[{"type":"text","text":"Ada banyak alasan mengapa kami menjadi pilihan utama sewa tenda di Solo:"}]},{"type":"paragraph","content":[{"type":"text","text":"✅ Berpengalaman sejak 1998 – Sudah puluhan tahun melayani warga Solo"}]},{"type":"paragraph","content":[{"type":"text","text":"✅ Harga murah dan transparan – Tanpa biaya tersembunyi"}]},{"type":"paragraph","content":[{"type":"text","text":"✅ Armada lengkap dan terawat – Tenda bersih, rapi, dan layak pakai"}]},{"type":"paragraph","content":[{"type":"text","text":"✅ Tim profesional – Pemasangan dan pembongkaran cepat dan aman"}]},{"type":"paragraph","content":[{"type":"text","text":"✅ Tersedia cabang Sukoharjo – Melayani lebih luas di Solo Raya"}]},{"type":"paragraph","content":[{"type":"text","text":"✅ Mudah dihubungi – Via WhatsApp, Instagram, dan Facebook"}]},{"type":"paragraph","content":[{"type":"text","text":"Area Layanan"}]},{"type":"paragraph","content":[{"type":"text","text":"Kami melayani pengiriman dan pemasangan tenda di seluruh wilayah Solo Raya, meliputi:"}]},{"type":"paragraph","content":[{"type":"text","text":"Kota Solo / Surakarta"}]},{"type":"paragraph","content":[{"type":"text","text":"Sukoharjo"}]},{"type":"paragraph","content":[{"type":"text","text":"Karanganyar"}]},{"type":"paragraph","content":[{"type":"text","text":"Boyolali"}]},{"type":"paragraph","content":[{"type":"text","text":"Klaten"}]},{"type":"paragraph","content":[{"type":"text","text":"Wonogiri"}]},{"type":"paragraph","content":[{"type":"text","text":"Sragen"}]},{"type":"paragraph","content":[{"type":"text","text":"Cara Pesan Sewa Tenda Solo Murah"}]},{"type":"paragraph","content":[{"type":"text","text":"Proses pemesanan sangat mudah dan cepat:"}]},{"type":"paragraph","content":[{"type":"text","text":"Hubungi kami via WhatsApp 0851-6363-3221"}]},{"type":"paragraph","content":[{"type":"text","text":"Sampaikan jenis acara, tanggal, dan lokasi"}]},{"type":"paragraph","content":[{"type":"text","text":"Kami berikan rekomendasi paket tenda terbaik"}]},{"type":"paragraph","content":[{"type":"text","text":"Sepakati harga dan lakukan konfirmasi pemesanan"}]},{"type":"paragraph","content":[{"type":"text","text":"Tim kami datang tepat waktu untuk pemasangan"}]},{"type":"paragraph","content":[{"type":"text","text":"Hubungi Kami Sekarang"}]},{"type":"paragraph","content":[{"type":"text","text":"Jangan tunda persiapan acara Anda! Segera hubungi Totok Sri Murni untuk mendapatkan penawaran sewa tenda Solo murah terbaik."}]},{"type":"paragraph","content":[{"type":"text","text":"📞 WhatsApp: 0851-6363-3221"}]},{"type":"paragraph","content":[{"type":"text","text":"📍 Alamat: Jalan Sri Narendra No. 20b, Solo"}]},{"type":"paragraph","content":[{"type":"text","text":"🌐 Website: totoksrimurnisewatendasolo.biz.id"}]},{"type":"paragraph","content":[{"type":"text","text":"📷 Instagram: @persewaan_solo"}]}]}', 1, NULL, '2026-07-14 15:32:48', '2026-07-14 15:44:44', '', 'Baju, Kain', '', 'React.js', 0);
