INSERT INTO CV (id, title, slug, data, published, sort_order, createdAt, updatedAt) VALUES ('db330177-85e0-40bc-a6fb-bfc44ad5fe50', 'AraZhar - Web Developer', 'web-developer', '{"photo":"/api/admin/media/1784048219688-u30lre.jpeg","location":"Nunukan, Kalimantan Utara, Indonesia","email":"admin@gdsi.my.id","phone":"+6285175229977","website":"https://azr.is-a.dev","bio":"Independent Web Developer asal Nunukan, Kalimantan Utara. \nBerpengalaman membangun web modern menggunakan Next.js dan \nCloudflare. Passionate dalam desain retro/Y2K dan pixel art. \nMengerjakan semua proyek sepenuhnya dari Android — membuktikan \nbahwa kreativitas tidak bergantung pada perangkat.","skills":[{"name":"Next.js","level":80},{"name":"Cloudflare Pages & Workers","level":80},{"name":"HTML & CSS","level":90},{"name":"JavaScript","level":75},{"name":"GitHub","level":75},{"name":"UI/UX Design (Y2K/Retro)","level":85},{"name":"SEO On-Page","level":70},{"name":"Web Monetization","level":70}],"experience":[{"position":"Fullstack Developer","company":"DownTepi (Personal Project)","period":"2025 – Sekarang","desc":"Membangun multi-platform video downloader             (TikTok, Instagram, YouTube, Twitter/X, Facebook)             menggunakan Cobalt sebagai backend engine.             Desain Y2K retro dengan Press Start 2P font.            Domain: down.tepi.my.id"}],"education":[{"school":"SMKN 1 Nunukan","degree":"Multimedia Desain Grafis Percetakan","year":"2020"}]}', 1, 0, '2026-07-14 17:07:58', '2026-07-16 13:22:35');
